  ('dietitian-moex-03300', 'dietitian', 'dietitian-moex-102-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關膽固醇的敘述，何者錯誤？', '["可經陽光照射，在皮膚上形成維生素D", "主要運輸型態為游離膽固醇", "可於肝臟代謝成膽酸", "可轉換成性激素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "c4c4a20fa551", "answer_pdf_sha1": "e0664812025d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03301', 'dietitian', 'dietitian-moex-102-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '脂肪到達小腸會分泌何種激素刺激膽囊釋出膽汁及胰臟分泌脂肪酶？', '["Cortisol", "Cholecystokinin", "Testosterone", "Glucagon"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "c4c4a20fa551", "answer_pdf_sha1": "e0664812025d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03302', 'dietitian', 'dietitian-moex-102-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '建議攝取量（recommended dietary allowance, RDA）是表示：', '["滿足特定年齡層或性別的健康人群中之50%人口的營養素攝取量之平均值", "因資料不足，對某特定年齡層大約可以使所有人維持一定的營養狀態", "滿足某一年齡層或性別的健康人群中之97～98%人的一天營養素攝取量", "對大多數健康者，每日營養素的最大可攝取量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:01+00:00", "source_pdf_sha1": "c4c4a20fa551", "answer_pdf_sha1": "e0664812025d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
